bool isValidParenthesisString(string parenthesisString) {
        int low = 0, high = 0;
        for (char c : parenthesisString) {
            if (c == '(') {
                low++;
                high++;
            } else if (c == ')') {
                if (low > 0) low--;
                high--;
            } else {
                if (low > 0) low--;
                high++;
            }
            if (high < 0) return false;
        }
        return low == 0;
    }

code.Python3:
class Solution:
    def isValidParenthesisString(self, parenthesisString: str) -> bool:
        low = high = 0

        for c in parenthesisString:
            if c == '(':
                low += 1
                high += 1
            elif c == ')':
                low = max(low - 1, 0)
                high -= 1
            else:  # '*'
                low = max(low - 1, 0)
                high += 1

            if high < 0:
                return False

        return low == 0

code.C:
bool dfs(const char *parenthesisString, int index, int openCount, int len, int memo[][101]) {
    if (openCount < 0) return false;            // can't have negative '('
    if (index == len) return openCount == 0;    // valid only if balanced

    if (memo[index][openCount] != -1)          // memoized result
        return memo[index][openCount];

    bool res = false;
    char c = parenthesisString[index];

    if (c == '(') {
        res = dfs(parenthesisString, index + 1, openCount + 1, len, memo);
    } 
    else if (c == ')') {
        res = dfs(parenthesisString, index + 1, openCount - 1, len, memo);
    } 
    else {  // '*'
        res = dfs(parenthesisString, index + 1, openCount + 1, len, memo) || // treat as '('
              dfs(parenthesisString, index + 1, openCount, len, memo)     || // treat as empty
              dfs(parenthesisString, index + 1, openCount - 1, len, memo);   // treat as ')'
    }

    memo[index][openCount] = res;
    return res;
}

bool isValidParenthesisString(char *parenthesisString) {
    int len = strlen(parenthesisString);
    int memo[101][101];

    // initialize memo table with -1
    for (int i = 0; i <= len; i++) {
        for (int j = 0; j <= len; j++) {
            memo[i][j] = -1;
        }
    }

    return dfs(parenthesisString, 0, 0, len, memo);
}

code.Java:
public boolean isValidParenthesisString(String parenthesisString) {
    int low = 0, high = 0;

    for (char c : parenthesisString.toCharArray()) {
        if (c == '(') {
            low++;
            high++;
        } 
        else if (c == ')') {
            if (low > 0) low--;  // match a '('
            high--;             // must reduce the upper bound
            if (high < 0) return false;  // too many ')'
        }
        else { // '*'
            if (low > 0) low--;  // treat '*' as ')'
            high++;              // or treat '*' as '('
        }
    }
    return low == 0;
}

